export default function FailurePlaceholder({
  className,
  text,
  iconSize = 48,
  showTimestamp = false,
  timestamp,
  onClick
}: FailurePlaceholderProps) {
  const t = useTranslations('Common');
  const textContent = text || t('failure');
  return (
    <div
      className={cn(
        'relative flex flex-col items-center justify-center rounded-lg bg-[#faf8ff] overflow-hidden',
        onClick && 'cursor-pointer hover:opacity-70 transition-opacity',
        className
      )}
      onClick={onClick}
    >
      {showTimestamp && timestamp && (
        <div className="absolute-top-center absolute z-30 flex w-full flex-nowrap items-center justify-center text-xs text-color-100/40">
          {timestamp}
        </div>
      )}

      <div className="flex flex-col items-center justify-center gap-2 p-2">
        <FailureIcon size={iconSize} />
        <p className="text-xs text-[#bfbfbf] text-center font-normal">
          {textContent}
        </p>
      </div>
    </div>
  );
}